 920→router.post('/update-username', requireAuth, async (req, res) => {
 921→    const userId = req.userId;
 922→    const { username } = req.body;
 923→
 924→    if (!username || typeof username !== 'string') {
 925→        return res.status(400).json({ error: 'username is required' });
 926→    }
 927→
 928→    const trimmed = username.trim();
 929→    if (trimmed.length < 3 || trimmed.length > 50) {
 930→        return res.status(400).json({ error: 'username must be 3-50 characters' });
 931→    }
 932→
 933→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
 934→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
 935→    }
 936→
 937→    const normalized = trimmed.toLowerCase();
 938→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
 939→    if (RESERVED_WORDS.includes(normalized)) {
 940→        return res.status(400).json({ error: 'this username is reserved' });
 941→    }
 942→
 943→    // Check uniqueness
 944→    const { data: existing } = await supabase
 945→        .from('users')
 946→        .select('id')
 947→        .ilike('username', normalized)
 948→        .neq('id', userId)
 949→        .limit(1);
 950→
 951→    if (existing && existing.length > 0) {
 952→        return res.status(409).json({ error: 'username is already taken' });
 953→    }
 954→
 955→    const { error: updateError } = await supabase
 956→        .from('users')
 957→        .update({ username: trimmed.toLowerCase() })
 958→        .eq('id', userId);
